bash -lc ' file="/etc/ssh/sshd_config"; perm_mask="0177"; maxperm="$(printf "%o" "$((0777 & ~perm_mask))")";
if [ ! -e "$file" ]; then
  echo "$file NO existe";
  exit 1;
fi;
mode="$(stat -Lc "%#a" "$file")"; owner="$(stat -Lc "%U" "$file")"; group="$(stat -Lc "%G" "$file")"; mode_num=$((8#$mode));
fail=0; msg="";
if [ $(( mode_num & perm_mask )) -gt 0 ]; then
  msg="$msg - Permisos actuales: $mode ; esperado: $maxperm o más restrictivo\n";
  fail=1;
fi;
if [ "$owner" != "root" ]; then
  msg="$msg - Owner actual: $owner ; esperado: root\n";
  fail=1;
fi;
if [ "$group" != "root" ]; then
  msg="$msg - Grupo actual: $group ; esperado: root\n";
  fail=1;
fi;
if [ "$fail" -eq 0 ]; then
  echo -e "$file existe (stat)\nCorrecto: permisos ($mode), owner ($owner), grupo ($group)";
else
  echo -e "$file existe (stat)\nIncorrecto:\n$msg";
  exit 1;
fi '

bash -lc ' l_ssh_group_name="$(awk -F: '"'"'($1 ~ /^(ssh_keys|_?ssh)$/) {print $1; exit}'"'"' /etc/group)";
found=0;
while IFS= read -r -d $'\''\0'\'' f; do
  if ssh-keygen -lf "$f" >/dev/null 2>&1 && file "$f" | grep -Piq '"'"'\bopenssh\h+([^#\n\r]+\h+)?private\h+key\b'"'"'; then

    found=1;
    mode=$(stat -Lc "%#a" "$f");
    owner=$(stat -Lc "%U" "$f");
    group=$(stat -Lc "%G" "$f");

    [ "$group" = "$l_ssh_group_name" ] && pmask=0137 || pmask=0177;

    if [ $(( 8#$mode & pmask )) -eq 0 ] && \
      [ "$owner" = "root" ] && \
      [[ "$group" = "root" || "$group" = "$l_ssh_group_name" ]]; then

        echo "$f (private key) - Correcto: permisos ($mode), owner ($owner), grupo ($group)";
    else
        echo "$f (private key) - Incorrecto: permisos ($mode), owner ($owner), grupo ($group)";
    fi
  fi
done < <(find -L /etc/ssh -xdev -type f -print0 2>/dev/null);
[ "$found" -eq 0 ] && echo "No se encontraron llaves privadas OpenSSH en /etc/ssh" '

bash -lc ' found=0;
while IFS= read -r -d $'\''\0'\'' f; do
  if ssh-keygen -lf "$f" >/dev/null 2>&1 && file "$f" | grep -Piq '"'"'\bopenssh\h+([^#\n\r]+\h+)?public\h+key\b'"'"'; then

    found=1;
    mode=$(stat -Lc "%#a" "$f");
    owner=$(stat -Lc "%U" "$f");
    group=$(stat -Lc "%G" "$f");

    if [ $(( 8#$mode & 0133 )) -eq 0 ] && [ "$owner" = "root" ] && [ "$group" = "root" ]; then
      echo "$f (public key) - Correcto: permisos ($mode), owner ($owner), grupo ($group)";
    else
      echo "$f (public key) - Incorrecto: permisos ($mode), owner ($owner), grupo ($group)";
    fi
  fi
done < <(find -L /etc/ssh -xdev -type f -print0 2>/dev/null);
[ "$found" -eq 0 ] && echo "No se encontraron llaves públicas OpenSSH en /etc/ssh" '

