bash -lc ' out=""; fail=0;
difok_line=$(grep -Psi -- "^\h*difok\h*=\h*([2-9]|[1-9][0-9]+)\b" /etc/security/pwquality.conf /etc/security/pwquality.conf.d/*.conf 2>/dev/null | head -n1); minlen_line=$(grep -Psi -- "^\h*minlen\h*=\h*(1[4-9]|[2-9][0-9]|[1-9][0-9]{2,})\b" /etc/security/pwquality.conf /etc/security/pwquality.conf.d/*.conf 2>/dev/null | head -n1);
if [ -n "$difok_line" ]; then
  out="$out\n- difok cumple: $difok_line";
else
  out="$out\n- difok NO cumple (se espera difok >= 2)";
  fail=1;
fi;
if [ -n "$minlen_line" ]; then
  out="$out\n- minlen cumple: $minlen_line";
else
  out="$out\n- minlen NO cumple (se espera minlen >= 14)";
  fail=1;
fi;
for p in dcredit ucredit lcredit ocredit; do
  line=$(grep -Psi -- "^\h*${p}\h*=\h*-[1-9][0-9]*\b" /etc/security/pwquality.conf /etc/security/pwquality.conf.d/*.conf 2>/dev/null | head -n1);
  if [ -n "$line" ]; then
    out="$out\n- $p cumple: $line";
  else
    out="$out\n- $p NO cumple (debe estar en valor negativo, no 0 ni mayor)";
    fail=1;
  fi;
done;
if [ "$fail" -eq 0 ]; then
  echo -e "PASS$out";
else
  echo -e "FAIL$out";
  exit 1;
fi '

bash -lc ' fail=0; out="";
conf_line=$(grep -Pi -- "^\h*remember\h*=\h*(2[4-9]|[3-9][0-9]|[1-9][0-9]{2,})\b" /etc/security/pwhistory.conf 2>/dev/null | head -n1);
if [ -n "$conf_line" ]; then
  out="$out\n- pwhistory.conf cumple: $conf_line";
else
  out="$out\n- /etc/security/pwhistory.conf NO cumple (se espera remember = 24 o mayor)";
  fail=1;
fi;
pam_lines=$(grep -Pi -- "^\h*password\h+(requisite|required|sufficient)\h+pam_pwhistory\.so\h+.*\bremember=\d+\b" /etc/pam.d/system-auth /etc/pam.d/password-auth 2>/dev/null);
if [ -z "$pam_lines" ]; then
  out="$out\n- system-auth y password-auth cumplen: pam_pwhistory.so no tiene argumento remember";
else
  out="$out\n- Se encontró remember= dentro de pam_pwhistory.so en PAM, y debe eliminarse:\n$pam_lines";
  fail=1;
fi;
if [ "$fail" -eq 0 ]; then
  echo -e "PASS$out";
else
  echo -e "FAIL$out";
  exit 1;
fi '

