bash -lc '
  min=$(awk "/^[[:space:]]*UID_MIN[[:space:]]+/{print \$2}" /etc/login.defs);

  excl_data=$(for u in root tux proactiva iacolcoauto ansible_test halt shutdown sync nfsnobody; do
    shell=$(getent passwd "$u" | awk -F: "{print \$7}");
    [ -z "$shell" ] && shell="not_found";

    pstat=$(passwd -S "$u" 2>/dev/null | awk "{print \$2}");
    if [ "$pstat" = "L" ]; then
      locked="yes";
    elif [ -z "$pstat" ]; then
      locked="unknown";
    else
      locked="no";
    fi;

    echo "${u}:shell=${shell},locked=${locked}";
  done | paste -sd "; " -);

  awk -F: -v m="$min" \
      -v ex="^(root|tux|proactiva|iacolcoauto|ansible_test|halt|shutdown|sync|nfsnobody)$" \
      -v re="^(/usr)?/sbin/nologin(/)?$|^(/usr)?/bin/false(/)?$" \
  "
  BEGIN{bad=0}
  (\$3<m && \$1!~ex){
    if (\$7 !~ re) { print \"bad:\" \$1 \":\" \$7; bad=1 }
  }
  END{
    if(bad==0) {
      print \"All system accounts use nologin/false\"
    }
    exit bad
  }
  " /etc/passwd

  echo "exclusions=${excl_data}"
'

bash -lc ' result=$(grep -Psi -- "^\h*umask\h+((\d{1,2}(\d[^7]|[^2-7]\d)\b)|(u=[rwx]{1,3},)?(((g=[rx]?[rx]?w[rx]?[rx]?\b)(,o=[rwx]{1,3})?)|((g=[wrx]{1,3},)?o=[wrx]{1,3}\b)))" /root/.bash_profile /root/.bashrc 2>/dev/null);
if [ -z "$result" ]; then
  echo "PASS - No se encontraron umask menos restrictivos que 0027 en /root/.bash_profile y /root/.bashrc";
else
  echo -e "FAIL - Se encontraron umask inseguros en archivos de root:\n$result";
  exit 1;
fi '

bash -lc ' files="/etc/bashrc /etc/profile /etc/profile.d/*.sh";
tmout=$(grep -Po "^\s*TMOUT=\d+" $files 2>/dev/null | head -1 | cut -d= -f2); readonly_set=$(grep -P "^\s*(readonly\s+TMOUT|typeset\s+-xr\s+TMOUT=)" $files 2>/dev/null | head -1); export_set=$(grep -P "^\s*(export\s+TMOUT|typeset\s+-xr\s+TMOUT=)" $files 2>/dev/null | head -1);
if [ -z "$tmout" ]; then
  echo "FAIL - TMOUT no está configurado";
  exit 1;
fi;
if [ "$tmout" -le 0 ] || [ "$tmout" -gt 900 ]; then
  echo "FAIL - TMOUT incorrecto: $tmout (debe ser <=900 y >0)";
  exit 1;
fi;
if [ -z "$readonly_set" ]; then
  echo "FAIL - TMOUT no está en readonly";
  exit 1;
fi;
if [ -z "$export_set" ]; then
  echo "FAIL - TMOUT no está en export";
  exit 1;
fi;
echo "PASS - TMOUT=$tmout correctamente configurado (readonly/export)" '
